have h₁ : (t + s) + u = u + (t + s), apply add_comm,
have h₂ : P((t + s) + u), apply add_comm_congr_right,
from eq.sub P h₁ h₂,

  let f : ℕ → ℕ := λ x, (s + x) * t,
